DELIMITER $$

create procedure info_alumno(cedula varchar(10))

BEGIN

if(exists(select * from alumno where num_cedula=cedula))

then select nombre, apellido from alumno where num_cedula=cedula;

elseif(not exists(select * from alumno where num_cedula=cedula))

then select 'El alumno no está matriculado' as 'Observación';

end if;

END $$

